{
  "grammar": [
    {
      "pattern": "Subject + Verb + Object + 了",
      "structure": ["Subject", "Verb", "Object", "了"],
      "explanation_en": "Use '了' at the end of a sentence to indicate that an action has been completed. This is the basic past tense marker in Chinese.",
      "title": "Completed Action with 了",
      "meaning": "Indicates an action is completed",
      "when_to_use": ["When talking about something you finished doing", "When reporting what happened", "When answering 'what did you do?'"],
      "when_not_to_use": ["When describing habitual actions", "When talking about future plans", "When using negated past actions (use 没有 instead)"],
      "pragmatic_notes": "In Taiwan, 了 is commonly used in casual conversation to confirm completion. It's less formal than using 已經 (already).",
      "word_order_notes": "了 always comes at the end of the sentence, after the object. Do not place it between the verb and object.",
      "english_contrast": "English uses past tense verb forms (e.g., 'ate', 'drank'), while Chinese adds 了 at the end of the sentence.",
      "korean_contrast": "Korean uses '-었/았다' attached to the verb stem, while Chinese uses 了 at the end of the sentence.",
      "negative_examples": [
        {
          "text": "我昨天吃早餐了。",
          "error": "This sentence is correct. No error."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我吃了早餐昨天。",
          "error": "Time word '昨天' should come before the verb, not at the end."
        },
        {
          "text": "我吃早餐了昨天。",
          "error": "Time word '昨天' should come before the verb, not after the object."
        }
      ],
      "transformation_drills": ["Change '我吃早餐' to past tense using 了.", "Change '他看電影' to past tense using 了."],
      "production_drills": ["Tell your partner what you ate for breakfast yesterday.", "Tell your partner what you did yesterday afternoon."],
      "common_error_patterns": ["Placing 了 after the verb instead of at the end", "Using 了 with 没有 in negative sentences"],
      "repair_feedback": {
        "word_order": "Remember: 了 goes at the end of the sentence, not after the verb.",
        "politeness": "This structure is neutral in politeness.",
        "vocabulary": "Use action verbs like 吃, 喝, 看, 去 with this pattern."
      }
    },
    {
      "pattern": "昨天 / 上個禮拜 / 上個月 + Subject + Verb + Object + 了",
      "structure": ["Time word", "Subject", "Verb", "Object", "了"],
      "explanation_en": "Use a past time word at the beginning of the sentence to specify when the action happened. Common time words include 昨天 (yesterday), 上個禮拜 (last week), 上個月 (last month), 剛才 (just now).",
      "title": "Past Time Words with 了",
      "meaning": "Specifies when a past action occurred",
      "when_to_use": ["When you want to specify the time of a past action", "When telling a story about yesterday or last week", "When answering 'when did you do that?'"],
      "when_not_to_use": ["When the time is obvious from context", "When talking about future events", "When using 今天 (today) for actions not yet completed"],
      "pragmatic_notes": "In Taiwan, 昨天 is very common in daily conversation. You can also use 上個禮拜 for last week or 上個月 for last month.",
      "word_order_notes": "Time word comes first in the sentence, before the subject. This is different from English where time can come at the end.",
      "english_contrast": "English can place time words at the beginning or end (e.g., 'I ate breakfast yesterday' or 'Yesterday I ate breakfast'). Chinese requires time words at the beginning.",
      "korean_contrast": "Korean places time words before the verb but after the subject (e.g., '나는 어제 아침을 먹었다'), while Chinese places time words at the very beginning.",
      "negative_examples": [
        {
          "text": "我昨天吃早餐了。",
          "error": "This sentence is correct. No error."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我吃早餐了昨天。",
          "error": "Time word '昨天' must come at the beginning of the sentence, not at the end."
        },
        {
          "text": "昨天我吃早餐。",
          "error": "Missing 了 to indicate the action is completed."
        }
      ],
      "transformation_drills": ["Add '昨天' to the sentence '我喝咖啡了'.", "Change '我上個禮拜看電影了' to use '昨天'."],
      "production_drills": ["Tell your partner what you did last week.", "Tell your partner what you did yesterday morning."],
      "common_error_patterns": ["Placing time word at the end of the sentence", "Forgetting 了 when using a past time word"],
      "repair_feedback": {
        "word_order": "Time word must come first, before the subject.",
        "politeness": "This structure is neutral in politeness.",
        "vocabulary": "Use time words like 昨天, 上個禮拜, 上個月, 剛才."
      }
    },
    {
      "pattern": "Subject + Verb + Object + 了，然後 + Subject + Verb + Object + 了",
      "structure": ["Subject", "Verb", "Object", "了", "然後", "Subject", "Verb", "Object", "了"],
      "explanation_en": "Use 然後 (then) to connect two completed actions in sequence. Both actions should end with 了 to indicate they are completed.",
      "title": "Sequencing Past Actions with 然後",
      "meaning": "Describes a sequence of past events",
      "when_to_use": ["When telling a story about what you did in order", "When describing your daily routine yesterday", "When explaining a series of past actions"],
      "when_not_to_use": ["When actions happened at the same time", "When describing future plans", "When using 先 (first) and 再 (then) for future actions"],
      "pragmatic_notes": "In Taiwan, 然後 is very common in spoken Chinese to connect events. It's similar to 'and then' in English.",
      "word_order_notes": "Each clause follows the Subject + Verb + Object + 了 pattern. 然後 connects the two clauses.",
      "english_contrast": "English uses 'and then' or 'then' to connect past actions. Chinese uses 然後 between two clauses, each ending with 了.",
      "korean_contrast": "Korean uses '-고' or '-서' to connect sequential actions (e.g., '먹고 갔다'), while Chinese uses 然後 between separate clauses.",
      "negative_examples": [
        {
          "text": "我吃早餐了，然後我喝咖啡了。",
          "error": "This sentence is correct. No error."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我吃早餐了，然後喝咖啡了。",
          "error": "Missing subject '我' before '喝咖啡了' in the second clause."
        },
        {
          "text": "我吃早餐，然後我喝咖啡了。",
          "error": "First action '吃早餐' is missing 了 to indicate completion."
        }
      ],
      "transformation_drills": ["Combine '我起床了' and '我刷牙了' using 然後.", "Combine '我看電視了' and '我睡覺了' using 然後."],
      "production_drills": ["Tell your partner what you did after you got home yesterday.", "Tell your partner your morning routine yesterday using 然後."],
      "common_error_patterns": ["Omitting the subject in the second clause", "Forgetting 了 in one of the clauses"],
      "repair_feedback": {
        "word_order": "Each clause must have its own subject and end with 了.",
        "politeness": "This structure is neutral in politeness.",
        "vocabulary": "Use action verbs like 起床, 刷牙, 吃, 喝, 看, 去 with this pattern."
      }
    }
  ]
}
